{"path":"frontend/app/components/WifiCard.tsx","content":"'use client';

interface WifiCardProps {
  ssid: string | null;
  bssid: string | null;
  rssi: number | null;
  channel: number | null;
  tx_rate: number | null;
  security: string;
}

const WifiCard: React.FC<WifiCardProps> = (props) => {
  const { ssid, bssid, rssi, channel, tx_rate, security } = props;

  const getRssiColor = (rssi: number | null) => {
    if (rssi === null) return 'text-gray-500';
    if (rssi >= -50) return 'text-green-500';
    if (rssi >= -65) return 'text-yellow-500';
    return 'text-red-500';
  };

  const getRssiStrength = (rssi: number | null) => {
    if (rssi === null) return 'Not connected';
    if (rssi >= -50) return 'Excellent';
    if (rssi >= -65) return 'Good';
    if (rssi >= -75) return 'Fair';
    return 'Weak';
  };

  return (
    <div className="bg-white rounded-xl shadow-lg p-6 max-w-md w-full">
      <h2 className="text-2xl font-bold text-gray-800 mb-4">Wi-Fi Information</h2>

      <div className="space-y-3">
        <div className="flex justify-between items-center">
          <span className="text-gray-600 font-medium">Network Name:</span>
          <span className="font-semibold">{ssid || 'N/A'}</span>
        </div>

        <div className="flex justify-between items-center">
          <span className="text-gray-600 font-medium">BSSID:</span>
          <span className="font-mono text-sm">{bssid || 'N/A'}</span>
        </div>

        <div className="flex justify-between items-center">
          <span className="text-gray-600 font-medium">Signal Strength:</span>
          <div className="flex items-center">
            <span className={`font-semibold ${getRssiColor(rssi)}`}>
              {rssi !== null ? `${rssi} dBm` : 'N/A'}
            </span>
            <span className="ml-2 text-sm text-gray-500">
              ({getRssiStrength(rssi)})
            </span>
          </div>
        </div>

        <div className="flex justify-between items-center">
          <span className="text-gray-600 font-medium">Channel:</span>
          <span className="font-semibold">{channel !== null ? channel : 'N/A'}</span>
        </div>

        <div className="flex justify-between items-center">
          <span className="text-gray-600 font-medium">TX Rate:</span>
          <span className="font-semibold">{tx_rate !== null ? `${tx_rate} Mbps` : 'N/A'}</span>
        </div>

        <div className="flex justify-between items-center">
          <span className="text-gray-600 font-medium">Security:</span>
          <span className="font-semibold">{security}</span>
        </div>
      </div>
    </div>
  );
};

export default WifiCard;"}

{"path":"frontend/app/page.tsx","content":"'use client';

import { useEffect, useState } from 'react';
import WifiCard from './components/WifiCard';

interface WifiData {
  ssid: string | null;
  bssid: string | null;
  rssi: number | null;
  channel: number | null;
  tx_rate: number | null;
  security: string;
}

export default function Home() {
  const [wifiData, setWifiData] = useState<WifiData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchWifiData = async () => {
      try {
        const response = await fetch('http://localhost:8000/api/wifi');
        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }
        const data = await response.json();
        setWifiData(data);
      } catch (err) {
        setError('Failed to fetch Wi-Fi data');
        console.error('Error fetching Wi-Fi data:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchWifiData();

    // Refresh data every 5 seconds
    const interval = setInterval(fetchWifiData, 5000);
    return () => clearInterval(interval);
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500 mx-auto"></div>
          <p className="mt-4 text-gray-600">Loading Wi-Fi information...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex items-center justify-center">
        <div className="bg-white rounded-xl shadow-lg p-6 max-w-md w-full text-center">
          <div className="text-red-500 text-5xl mb-4">⚠️</div>
          <h2 className="text-2xl font-bold text-gray-800 mb-2">Error</h2>
          <p className="text-gray-600">{error}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex items-center justify-center p-4">
      <div className="flex flex-col items-center">
        <h1 className="text-3xl font-bold text-gray-800 mb-2">Wi-Fi Stats</h1>
        <p className="text-gray-600 mb-8">Real-time Wi-Fi network information</p>

        {wifiData && <WifiCard {...wifiData} />}

        <div className="mt-8 text-center text-gray-500 text-sm">
          <p>Data refreshes every 5 seconds</p>
        </div>
      </div>
    </div>
  );
}"}

